import React, { useState, useEffect } from "react";
import axios from "axios";
import { ThemeProvider, useTheme } from "./contexts/ThemeContext";

// Layout & Pages
import Layout from "./components/layout/Layout";
import AuthPage from "./pages/AuthPage";
import DashboardPage from "./pages/DashboardPage";
import GroupsPage from "./pages/GroupsPage";
import FilesPage from "./pages/FilesPage";
import PeersPage from "./pages/PeersPage";
import TransferProgress from "./components/ui/TransferProgress";
import WebRTCHandler from "./utils/webrtc";

import "./App.css";

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const getAPIBaseURL = () => {
  const hostname = window.location.hostname;
  const protocol = window.location.protocol || 'http:';
  if (process.env.REACT_APP_API_URL) return process.env.REACT_APP_API_URL;
  return `${protocol}//${hostname}:5000/api`;
};

const BASE_API = getAPIBaseURL();
axios.defaults.baseURL = BASE_API;
const API = axios.create({ baseURL: BASE_API, withCredentials: true });

function AppContent() {
  const { toggleTheme, isDark } = useTheme();
  const [token, setToken] = useState(localStorage.getItem("token") || "");
  const [user, setUser] = useState(null);

  // Navigation State
  const [view, setView] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Form states
  const [loginEmail, setLoginEmail] = useState("");
  const [loginPassword, setLoginPassword] = useState("");
  const [regUsername, setRegUsername] = useState("");
  const [regEmail, setRegEmail] = useState("");
  const [regPassword, setRegPassword] = useState("");
  const [isLogin, setIsLogin] = useState(true);

  // Global App States
  const [loading, setLoading] = useState(false);
  const [notification, setNotification] = useState(null);

  // Data states
  const [groups, setGroups] = useState([]);
  const [selectedGroup, setSelectedGroup] = useState(null);
  const [files, setFiles] = useState([]);
  const [peers, setPeers] = useState([]);
  const [stats, setStats] = useState({
    fileCount: 0,
    groupCount: 0,
    peersOnline: 0
  });

  // Group Form Data
  const [groupName, setGroupName] = useState("");
  const [groupDesc, setGroupDesc] = useState("");
  const [groupPrivacy, setGroupPrivacy] = useState(true);
  const [inviteCode, setInviteCode] = useState("");
  const [tags, setTags] = useState("");
  const [editingGroup, setEditingGroup] = useState(null);
  const [editGroupName, setEditGroupName] = useState("");
  const [editGroupDesc, setEditGroupDesc] = useState("");
  const [editGroupPrivacy, setEditGroupPrivacy] = useState(true);

  // Profile & Settings
  const [editUsername, setEditUsername] = useState("");
  const [editEmail, setEditEmail] = useState("");
  const [settingsTheme, setSettingsTheme] = useState("light");
  const [emailNotifications, setEmailNotifications] = useState(true);

  // Transfer states for TransferProgress visualizer
  const [activeTransfers, setActiveTransfers] = useState([]);

  // WebRTC
  const [webrtc, setWebrtc] = useState(null);
  const [webrtcPeers, setWebrtcPeers] = useState([]);

  /** ======================
   *  INIT & REAL-TIME
   ======================== */
  useEffect(() => {
    if (token) {
      API.defaults.headers.common["Authorization"] = `Bearer ${token}`;
      fetchUser();
    } else {
      const savedToken = localStorage.getItem("token");
      if (savedToken) {
        setToken(savedToken);
        API.defaults.headers.common["Authorization"] = `Bearer ${savedToken}`;
      }
    }
  }, [token]);

  useEffect(() => {
    if (user) {
      const interval = setInterval(() => {
        fetchGroups();
        fetchPeers();
        if (selectedGroup) fetchFiles(selectedGroup.id);
        if (view === "dashboard") fetchStats();
      }, 5000);

      // Initialize WebRTC
      const signalingUrl = getAPIBaseURL().replace('5000/api', '5002');
      const handler = new WebRTCHandler(
        signalingUrl,
        user._id,
        user.username,
        (peersList) => {
          setWebrtcPeers(peersList);
        },
        (progressUpdate) => {
          setActiveTransfers(prev => {
            const index = prev.findIndex(t => t.id === progressUpdate.id);
            if (index >= 0) {
              const updated = [...prev];
              updated[index] = progressUpdate;
              // Remove complete transfers after 3 seconds
              if (progressUpdate.status === 'complete') {
                setTimeout(() => {
                  setActiveTransfers(curr => curr.filter(t => t.id !== progressUpdate.id));
                }, 3000);
              }
              return updated;
            } else {
              if (progressUpdate.status === 'complete') return prev; // don't add completed ones right away
              return [...prev, progressUpdate];
            }
          });
        }
      );
      setWebrtc(handler);

      return () => {
        clearInterval(interval);
        handler.disconnect();
      };
    }
  }, [user]); // user is enough dependency here since we just want it once on login


  /** ======================
   *  NOTIFICATIONS
   ======================== */
  const notify = (msg, type = "success") => {
    setNotification({ msg, type });
    setTimeout(() => setNotification(null), 4000);
  };

  /** ======================
   *  API FETCHERS
   ======================== */
  const fetchUser = async () => {
    try {
      const res = await API.get("/auth/me");
      setUser(res.data);
      setEditUsername(res.data.username);
      setEditEmail(res.data.email);
      setSettingsTheme(res.data.theme || "light");
      setEmailNotifications(res.data.emailNotifications !== false);

      await API.post("/groups/join-network").catch(() => {});

      await fetchGroups();
      await fetchPeers();
      await fetchStats();
    } catch (err) {
      if (err.response?.status === 401 || err.response?.status === 403) logout();
    }
  };

  const fetchGroups = async () => {
    try {
      const res = await API.get("/groups");
      setGroups(res.data);
    } catch (err) {}
  };

  const fetchFiles = async (groupId) => {
    try {
      const res = await API.get(`/files/group/${groupId}`);
      setFiles(res.data);
    } catch (err) {}
  };

  const fetchPeers = async () => {
    try {
      const res = await API.get("/peers");
      setPeers(res.data);
    } catch (err) {}
  };

  const fetchStats = async () => {
    try {
      const res = await API.get("/stats/dashboard");
      setStats(res.data);
    } catch (err) {}
  };

  /** ======================
   *  AUTH COMMANDS
   ======================== */
  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const endpoint = isLogin ? "/auth/login" : "/auth/register";
      const data = isLogin
        ? { email: loginEmail, password: loginPassword }
        : { username: regUsername, email: regEmail, password: regPassword };

      const res = await API.post(endpoint, data);

      setToken(res.data.token);
      localStorage.setItem("token", res.data.token);
      setUser(res.data.user);
      setView("dashboard");
      notify("Welcome!");
    } catch (err) {
      notify(err.response?.data?.error || "Authentication failed", "error");
    }
    setLoading(false);
  };

  const logout = () => {
    setToken("");
    setUser(null);
    localStorage.removeItem("token");
    delete API.defaults.headers.common["Authorization"];
    notify("Logged out");
  };

  /** ======================
   *  PEER LOGIC
   ======================== */
  const connectToPeer = async (peerId, peerName) => {
    setLoading(true);
    try {
      // First register it with central API as intended
      await API.post("/peers/connect", { peerId });
      notify(`Connected to ${peerName}!`);
      fetchPeers();

      // Try negotiating direct WebRTC if they are in signaling layer
      if (webrtc) {
        const targetWrtpPeer = webrtcPeers.find(p => p.peerId === peerId || p.peerName === peerName);
        if (targetWrtpPeer) {
          webrtc.connectToPeer(targetWrtpPeer.socketId);
        }
      }
    } catch (err) {
      notify(err.response?.data?.error || "Failed to connect", "error");
    }
    setLoading(false);
  };

  /** ======================
   *  GROUP LOGIC
   ======================== */
  const createGroup = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await API.post("/groups/create", {
        name: groupName,
        description: groupDesc,
        isPrivate: groupPrivacy,
      });
      notify(`Group Created! Code: ${res.data.inviteCode}`);
      setGroupName("");
      setGroupDesc("");
      setGroupPrivacy(true);
      await fetchGroups();
      await fetchStats();
      setView("groups");
    } catch (err) {
      notify(err.response?.data?.error || "Failed to create group", "error");
    }
    setLoading(false);
  };

  const joinGroup = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const cleanInviteCode = inviteCode.trim().toUpperCase();
      if (!cleanInviteCode) {
        notify("Enter an invite code", "error");
        setLoading(false);
        return;
      }
      await API.post("/groups/join", { inviteCode: cleanInviteCode });
      notify("Joined group!");
      setInviteCode("");
      await fetchGroups();
      await fetchStats();
      setView("groups");
    } catch (err) {
      notify(err.response?.data?.error || "Invalid invite code", "error");
    }
    setLoading(false);
  };

  const selectGroup = (group) => {
    setSelectedGroup(group);
    setView("files");
    fetchFiles(group.id);
  };

  const deleteGroup = async (groupId, groupName) => {
    if (!window.confirm(`Delete group "${groupName}"?`)) return;
    setLoading(true);
    try {
      await API.delete(`/groups/${groupId}`);
      notify("Group deleted");
      if (selectedGroup?.id === groupId) {
        setSelectedGroup(null);
        setView("groups");
      }
      await fetchGroups();
      await fetchStats();
    } catch (err) {
      notify(err.response?.data?.error || "Delete failed", "error");
    }
    setLoading(false);
  };

  const startEditGroup = (group) => {
    setEditingGroup(group);
    setEditGroupName(group.name);
    setEditGroupDesc(group.description || "");
    setEditGroupPrivacy(group.isPrivate !== false);
  };

  const leaveGroup = async (groupId, groupName) => {
    if (!window.confirm(`Leave group "${groupName}"?`)) return;
    setLoading(true);
    try {
      await API.post(`/groups/${groupId}/leave`);
      notify("Left group successfully");
      if (selectedGroup?.id === groupId) {
        setSelectedGroup(null);
        setView("groups");
      }
      await fetchGroups();
      await fetchStats();
    } catch (err) {
      notify(err.response?.data?.error || "Leave failed", "error");
    }
    setLoading(false);
  };

  /** ======================
   *  FILE LOGIC
   ======================== */
  const uploadFileToGroup = async (e, file) => {
    e.preventDefault();
    if (!file) return notify("Select a file", "error");

    setLoading(true);

    // If we're on network share and have direct peers, use WebRTC Chunking instead!
    const networkGroup = groups.find(g => g.name === "__NETWORK_SHARE__");
    if (selectedGroup && networkGroup && selectedGroup.id === networkGroup.id && webrtc && webrtcPeers.length > 0) {
      // Broadcast file dynamically to active WebRTC peers
      webrtcPeers.forEach(p => {
        webrtc.sendFile(p.socketId, file);
      });
      notify("Broadcasting file via WebRTC to local network P2P!");
      setLoading(false);
      return; 
    }

    // Otherwise standard API upload
    const formData = new FormData();
    formData.append("file", file);
    formData.append("groupId", selectedGroup.id);
    formData.append("tags", JSON.stringify(tags.split(",").map((t) => t.trim())));

    const dummyTransfer = { id: Date.now(), fileName: file.name, progress: 50, type: 'upload' };
    setActiveTransfers([dummyTransfer]);

    try {
      await API.post("/files/upload", formData);
      notify("File uploaded!");
      setTags("");
      await fetchFiles(selectedGroup.id);
      await fetchStats();
    } catch (err) {
      notify("Upload failed", "error");
    }
    setActiveTransfers([]);
    setLoading(false);
  };

  const downloadFile = async (id, name) => {
    try {
      const dummyTransfer = { id: Date.now(), fileName: name, progress: 30, type: 'download' };
      setActiveTransfers([dummyTransfer]);

      const res = await API.get(`/files/download/${id}`, { responseType: "blob" });
      const url = window.URL.createObjectURL(new Blob([res.data]));
      const link = document.createElement("a");
      link.href = url;
      link.download = name;
      link.click();
      notify("Downloaded!");
    } catch (err) {
      notify("Download failed", "error");
    }
    setActiveTransfers([]);
  };

  const deleteFile = async (id) => {
    if (!window.confirm("Delete this file?")) return;
    try {
      await API.delete(`/files/${id}`);
      notify("File deleted");
      await fetchFiles(selectedGroup.id);
      await fetchStats();
    } catch {
      notify("Delete failed", "error");
    }
  };

  /** ======================
   *  FORMATTERS
   ======================== */
  const formatSize = (bytes) => {
    if (!bytes) return "0 MB";
    const mb = bytes / (1024 * 1024);
    if (mb >= 1024) return `${(mb / 1024).toFixed(2)} GB`;
    if (mb >= 1) return `${mb.toFixed(2)} MB`;
    return `${(bytes / 1024).toFixed(2)} KB`;
  };

  const formatDate = (d) => new Date(d).toLocaleString();


  /** ======================
   *  RENDER APP
   ======================== */
  if (!token || !user) {
    return (
      <AuthPage 
        isLogin={isLogin} setIsLogin={setIsLogin}
        loginEmail={loginEmail} setLoginEmail={setLoginEmail}
        loginPassword={loginPassword} setLoginPassword={setLoginPassword}
        regUsername={regUsername} setRegUsername={setRegUsername}
        regEmail={regEmail} setRegEmail={setRegEmail}
        regPassword={regPassword} setRegPassword={setRegPassword}
        handleAuth={handleAuth} loading={loading}
        notification={notification}
      />
    );
  }

  return (
    <Layout
      user={user}
      isDark={isDark}
      toggleTheme={toggleTheme}
      onLogout={logout}
      onProfileClick={() => setView("profile")}
      onSettingsClick={() => setView("settings")}
      sidebarOpen={sidebarOpen}
      setSidebarOpen={setSidebarOpen}
      view={view}
      setView={setView}
      groups={groups}
      peers={peers}
      selectedGroup={selectedGroup}
      selectGroup={selectGroup}
    >
      <TransferProgress activeTransfers={activeTransfers} />

      {view === "dashboard" && (
        <DashboardPage 
          stats={stats} 
          peersCount={peers.length} 
          groups={groups}
          setView={setView}
          selectGroup={selectGroup}
          fetchStats={fetchStats}
        />
      )}

      {(view === "groups" || view === "creategroup" || view === "joingroup") && (
        <GroupsPage
          groups={groups}
          groupName={groupName}
          setGroupName={setGroupName}
          groupDesc={groupDesc}
          setGroupDesc={setGroupDesc}
          groupPrivacy={groupPrivacy}
          setGroupPrivacy={setGroupPrivacy}
          inviteCode={inviteCode}
          setInviteCode={setInviteCode}
          createGroup={createGroup}
          joinGroup={joinGroup}
          selectGroup={selectGroup}
          deleteGroup={deleteGroup}
          leaveGroup={leaveGroup}
          startEditGroup={startEditGroup}
          loading={loading}
        />
      )}

      {view === "files" && selectedGroup && (
        <FilesPage
          selectedGroup={selectedGroup}
          files={files}
          uploadFileToGroup={uploadFileToGroup}
          tags={tags}
          setTags={setTags}
          downloadFile={downloadFile}
          deleteFile={deleteFile}
          formatSize={formatSize}
          formatDate={formatDate}
          loading={loading}
        />
      )}

      {view === "peers" && (
        <PeersPage
          peers={peers}
          connectToPeer={connectToPeer}
          loading={loading}
        />
      )}

      {/* Global Notification */}
      {notification && (
        <div className={`notification ${notification.type}`}>
          {notification.msg}
        </div>
      )}
    </Layout>
  );
}

function App() {
  return (
    <ThemeProvider>
      <AppContent />
    </ThemeProvider>
  );
}

export default App;
